-- SPEC:D.2 — compiled metric view: identified_purchase_rate (v1) @ grain=month · entity=semantic_order
-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW brain_serving.mv_metric_identified_purchase_rate_month AS
WITH base AS (
  SELECT
    brand_id,
    date_trunc('month', conversion_at) AS period,
    channel,
    SUM(CASE WHEN brain_id NOT LIKE 'anonymous%' THEN 1 ELSE 0 END) AS identified_orders,
    COUNT(DISTINCT order_id) AS total_orders
  FROM brain_serving.semantic_order
  WHERE conversion_at IS NOT NULL
    AND ${BRAND_PREDICATE}
  GROUP BY 1, 2, 3
)
SELECT
  brand_id,
  period,
  channel,
  identified_orders,
  total_orders,
  (CAST(identified_orders AS double) / NULLIF(total_orders, 0)) AS identified_purchase_rate
FROM base;
